    async def get_a_presigned_s3url_for_direct_file_upload(
        self,
        *,
        file_name: str,
        file_size: int,
        content_type: str,
        knowledge_base_id: str,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> PostKnowledgebaseGetPresignedUrlResponse:
        """
        Two-step file upload flow that bypasses Atoms' API for the file bytes themselves — useful when files exceed the multipart upload limit on `POST /knowledgebase/{id}/items/upload-media` or when you want to upload from the browser without round-tripping through your backend.

        **Step 1**: Call this endpoint with file metadata. Atoms returns a presigned URL + a storage `key`.
        **Step 2**: `PUT` the file bytes directly to the presigned URL (set `Content-Type` to the same value you sent here).
        **Step 3**: Call [`POST /knowledgebase/compelete-file-upload`](#operation/completeKnowledgeBaseFileUpload) with the same `key` to commit the upload and start processing.

        Same end result as `POST /knowledgebase/{id}/items/upload-media`, just without the multipart-through-our-API hop.

        Parameters
        ----------
        file_name : str
            Original filename — used for display in the Atoms dashboard. Doesn't have to match the S3 key.

        file_size : int
            Size in bytes. Atoms uses this to enforce per-file limits before issuing the URL.

        content_type : str
            MIME type. You must send this EXACT value as `Content-Type` on the subsequent PUT to the presigned URL.

        knowledge_base_id : str
            24-char hex ObjectId of the target knowledge base (from `GET /knowledgebase`).

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        PostKnowledgebaseGetPresignedUrlResponse
            Presigned URL ready — upload directly to it.

        Examples
        --------
        import asyncio

        from smallestai import AsyncSmallestAI

        client = AsyncSmallestAI(
            api_key="YOUR_API_KEY",
        )


        async def main() -> None:
            await client.atoms.knowledge_base.get_a_presigned_s3url_for_direct_file_upload(
                file_name="company-handbook.pdf",
                file_size=2457600,
                content_type="application/pdf",
                knowledge_base_id="6867ca76d0f8f2e0f4201281",
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.get_a_presigned_s3url_for_direct_file_upload(
            file_name=file_name,
            file_size=file_size,
            content_type=content_type,
            knowledge_base_id=knowledge_base_id,
            request_options=request_options,
        )
        return _response.data

    async def complete_a_presigned_url_upload_and_start_processing(
        self,
        *,
        file_name: str,
        content_type: str,
        knowledge_base_id: str,
        key: str,
        file_size: int,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> PostKnowledgebaseCompeleteFileUploadResponse:
        """
        Step 3 of the presigned-URL upload flow. Commits a file that was uploaded directly to S3 via `POST /knowledgebase/get-presigned-url`, registers it as a knowledge-base item, and triggers async processing.

        **Note**: The path includes `compelete` (sic) — that's the actual route name on the platform. Don't fix the spelling in your client; it's a stable URL.

        Parameters
        ----------
        file_name : str
            Filename — pass the same value used in `get-presigned-url`.

        content_type : str

        knowledge_base_id : str
            Target knowledge base ID.

        key : str
            S3 storage key returned by `get-presigned-url`.

        file_size : int

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        PostKnowledgebaseCompeleteFileUploadResponse
            File registered as a knowledge-base item. Processing runs async — poll `GET /knowledgebase/{id}/items` for the item to surface with the desired processing status.

        Examples
        --------
        import asyncio

        from smallestai import AsyncSmallestAI

        client = AsyncSmallestAI(
            api_key="YOUR_API_KEY",
        )


        async def main() -> None:
            await client.atoms.knowledge_base.complete_a_presigned_url_upload_and_start_processing(
                file_name="company-handbook.pdf",
                content_type="application/pdf",
                knowledge_base_id="6867ca76d0f8f2e0f4201281",
                key="key",
                file_size=1,
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.complete_a_presigned_url_upload_and_start_processing(
            file_name=file_name,
            content_type=content_type,
            knowledge_base_id=knowledge_base_id,
            key=key,
            file_size=file_size,
            request_options=request_options,
        )
        return _response.data

